479 |         function levenshtein(a, b) {
480 |             const matrix = [];
481 |             for (let i = 0; i <= b.length; i++) { matrix[i] = [i]; }
482 |             for (let j = 0; j <= a.length; j++) { matrix[0][j] = j; }
483 |             for (let i = 1; i <= b.length; i++) {
484 |                 for (let j = 1; j <= a.length; j++) {
485 |                     if (b.charAt(i - 1) == a.charAt(j - 1)) matrix[i][j] = matrix[i - 1][j - 1];
486 |                     else matrix[i][j] = Math.min(matrix[i - 1][j - 1] + 1, Math.min(matrix[i][j - 1] + 1, matrix[i - 1][j] + 1));
487 |                 }
488 |             }
489 |             return matrix[b.length][a.length];
490 |         }
